    12→
    13→@ExperimentalCoroutinesApi
    14→@Composable
    15→fun connectionState(): State<Boolean> {
    16→    // Creates a State<ConnectionState> with current connectivity state as initial value
    17→    return produceState(initialValue = AppService.isActive) {
    18→        // In a coroutine, can make suspend calls
    19→        observeConnectionAsFlow().collect { value = it }
    20→    }
    21→}
    22→
    23→@ExperimentalCoroutinesApi
    24→fun observeConnectionAsFlow() = callbackFlow {
    25→    val listener = object : ServiceListener {
    26→        override fun onServiceStarted() {
    27→            trySend(true)
    28→        }
    29→
    30→        override fun onServiceStopped() {
    31→            trySend(false)
    32→        }
    33→    }
    34→    AppService.addListener(listener)
    35→
    36→    // Set current state
    37→    trySend(AppService.isActive)
    38→
    39→    // Remove callback when not used
    40→    awaitClose {
    41→        AppService.removeListener(listener)
    42→    }
    43→}

