@OptIn(ExperimentalFoundationApi::class)
@Composable
fun AccountsScreen(navigationType: NavigationType) {
    val list = remember { AccountManager.accounts.toMutableStateList() }
    val refreshList = {
        list.clear()
        list.addAll(AccountManager.accounts)
        Unit
    }

    if (list.size != AccountManager.accounts.size) {
        refreshList()
    }

    val menuCreate = remember { mutableStateOf(false) }
    val snackbarHostState = remember { SnackbarHostState() }
    val scope = rememberCoroutineScope()

    Scaffold(
        topBar = {
            PHaxAppBar(
                title = stringResource(id = R.string.tab_accounts),
                navigationType = navigationType
            ) {}
        },
        floatingActionButton = {
            FloatingActionButton(onClick = { menuCreate.value = true }) {
                Icon(
                    imageVector = Icons.Default.Add,
                    contentDescription = stringResource(id = R.string.accounts_login)
                )
            }
        },
        snackbarHost = { SnackbarHost(snackbarHostState) }
    ) { innerPadding ->
        val dialogRename = remember { mutableStateOf<Account?>(null) }
        val dialogDelete = remember { mutableStateOf<Account?>(null) }

        DialogRename(dialogRename, refreshList)
        DialogDelete(dialogDelete, refreshList)
        MenuCreate(menuCreate, refreshList)

        LazyColumn(
            contentPadding = innerPadding,
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(list, key = { it.remark }) {
                Box(modifier = Modifier.animateItemPlacement()) {
                    val expanded = remember { mutableStateOf(false) }
                    ElevatedCard(
                        modifier = Modifier.padding(16.dp, 4.dp)
                    ) {
                        ListItem(
                            title = it.remark,
                            description = {
                                Row {
                                    Text(text = it.platform.deviceType, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                    if (it == AccountManager.currentAccount) {
                                        Text(
                                            stringResource(R.string.account_selected),
                                            modifier = Modifier.padding(6.dp, 0.dp),
                                            color = MaterialTheme.colorScheme.primary,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            },
                            onClick = {
                                if (it == AccountManager.currentAccount) {
                                    AccountManager.currentAccount = null
                                } else {
                                    AccountManager.currentAccount = it
                                }
                                refreshList()
                                scope.launch {
                                    snackbarHostState.showSnackbar(
                                        if (it == AccountManager.currentAccount) "Account deselected" else "Account selected: ${it.remark}"
                                    )
                                }
                            },
                            expanded = expanded
                        ) {
                            if (it == AccountManager.currentAccount) {
                                DropdownMenuItem(
                                    text = { Text(stringResource(R.string.config_deselect)) },
                                    onClick = {
                                        AccountManager.currentAccount = null
                                        refreshList()
                                        expanded.value = false
                                    },
                                    leadingIcon = { Icon(Icons.Outlined.CheckBoxOutlineBlank, contentDescription = null) }
                                )
                            } else {
                                DropdownMenuItem(
                                    text = { Text(stringResource(R.string.account_select)) },
                                    onClick = {
                                        AccountManager.currentAccount = it
                                        refreshList()
                                        expanded.value = false
                                    },
                                    leadingIcon = { Icon(Icons.Outlined.CheckBox, contentDescription = null) }
                                )
                            }
                            DropdownMenuItem(
                                text = { Text(stringResource(R.string.config_rename)) },
                                onClick = {
                                    dialogRename.value = it
                                    expanded.value = false
                                },
                                leadingIcon = { Icon(Icons.Outlined.Edit, contentDescription = null) }
                            )
                            DropdownMenuItem(
                                text = { Text(stringResource(R.string.config_delete)) },
                                onClick = {
                                    dialogDelete.value = it
                                    expanded.value = false
                                },
                                leadingIcon = { Icon(Icons.Outlined.Delete, contentDescription = null) }
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
private fun MenuCreate(state: MutableState<Boolean>, callback: () -> Unit) {
    Box(
        modifier = Modifier
            .fillMaxSize()
            .wrapContentSize(Alignment.TopEnd)
            .padding(12.dp, 0.dp),
        contentAlignment = Alignment.TopEnd
    ) {
        val loginActivityLauncher = rememberLauncherForActivityResult(MicrosoftLoginActivity.LauncherContract()) {
            callback()
        }

        DropdownMenu(
            expanded = state.value,
            onDismissRequest = { state.value = false }
        ) {
            XboxDeviceInfo.devices.values.forEach { device ->
                DropdownMenuItem(
                    text = { Text(stringResource(R.string.accounts_login_as, device.deviceType)) },
                    onClick = {
                        loginActivityLauncher.launch(device)
                    }
                )
            }
        }
    }
}

@Composable
private fun DialogRename(target: MutableState<Account?>, callback: () -> Unit) {
    val value = target.value
    if (value != null) {
        val name: MutableState<String?> = remember { mutableStateOf(null) }
        if (name.value == null) {
            name.value = value.remark
        }

        AlertDialog(
            onDismissRequest = { target.value = null },
            title = { Text(stringResource(R.string.config_rename_dialog_message)) },
            text = {
                TextField(
                    value = name.value ?: "",
                    onValueChange = { name.value = it },
                    trailingIcon = {
                        IconButton(onClick = { name.value = suggestRemark() }) {
                            Icon(Icons.Filled.Refresh, null)
                        }
                    }
                )
            },
            confirmButton = {
                TextButton(
                    enabled = isValidRemark(AccountManager.accounts.map { it.remark }, name.value ?: ""),
                    onClick = {
                        value.remark = name.value ?: ""
                        AccountManager.save()
                        target.value = null
                        name.value = null

                        callback()
                    }
                ) {
                    Text(stringResource(R.string.dialog_confirm))
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { target.value = null }
                ) {
                    Text(stringResource(R.string.dialog_cancel))
                }
            }
        )
    }
}

@Composable
private fun DialogDelete(target: MutableState<Account?>, callback: () -> Unit) {
    val value = target.value

    if (value != null) {
        AlertDialog(
            onDismissRequest = { target.value = null },
            title = { Text(stringResource(R.string.dialog_title)) },
            text = { Text(stringResource(R.string.account_delete_dialog_message, value.remark)) },
            confirmButton = {
                TextButton(
                    onClick = {
                        AccountManager.accounts.remove(value)
                        if (AccountManager.currentAccount == value) {
                            AccountManager.currentAccount = null
                        }
                        AccountManager.save()
                        target.value = null
                        callback()
                    }
                ) {
                    Text(stringResource(R.string.dialog_confirm))
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { target.value = null }
                ) {
                    Text(stringResource(R.string.dialog_cancel))
                }
            }
        )
    }
}

package dev.sora.protohax.relay.service

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.app.Service
import android.content.Intent
import android.graphics.BitmapFactory
import android.net.ConnectivityManager
import android.net.VpnService
import android.os.ParcelFileDescriptor
import android.view.WindowManager
import androidx.core.app.NotificationCompat
import dev.sora.protohax.MyApplication
import dev.sora.protohax.R
import dev.sora.protohax.relay.MinecraftRelay
import dev.sora.protohax.ui.activities.MainActivity
import dev.sora.protohax.ui.components.screen.settings.Settings
import dev.sora.protohax.util.ContextUtils.getApplicationName
import dev.sora.relay.utils.logError
import dev.sora.relay.utils.logInfo
import libmitm.Libmitm
import libmitm.TUN
import java.net.Inet4Address
import java.net.Inet6Address
import java.net.NetworkInterface


class AppService : VpnService() {

    private lateinit var windowManager: WindowManager

    private var vpnDescriptor: ParcelFileDescriptor? = null
    private var tun: TUN? = null

    override fun onCreate() {
        val notificationManager = getSystemService(Service.NOTIFICATION_SERVICE) as NotificationManager
        if (notificationManager.getNotificationChannel(CHANNEL_ID) == null) {
            notificationManager.createNotificationChannel(NotificationChannel(
                CHANNEL_ID, getString(
                    R.string.app_name
                ), NotificationManager.IMPORTANCE_LOW))
        }

        windowManager = getSystemService(WINDOW_SERVICE) as WindowManager

        MyApplication.overlayManager.currentContext = this
    }

    override fun onDestroy() {
        logInfo("VPN service destroyed")
        stopVPN()
        MyApplication.overlayManager.currentContext = null
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        intent ?: return START_NOT_STICKY

        val action = intent.action
        try {
            if (ACTION_START == action) {
                startVPN()
                startForeground(1, createNotification())
            } else {
                stopVPN()
                stopForeground(STOP_FOREGROUND_REMOVE)
                stopSelf()
            }
        } catch (t: Throwable) {
            logError("command", t)
        }
        return super.onStartCommand(intent, flags, startId)
    }

    private fun startVPN() {
        val (hasIPv4, hasIPv6) = when(Settings.ipv6Status.getValue(this)) {
            Settings.IPv6Choices.AUTOMATIC -> checkNetState()
            Settings.IPv6Choices.ENABLED -> true to true
            Settings.IPv6Choices.DISABLED -> true to false
            Settings.IPv6Choices.V6ONLY -> false to true
        }

        val builder = Builder()
        builder.setBlocking(true)
        builder.setMtu(VPN_MTU)
        builder.setSession("ProtoHax")
        builder.addAllowedApplication(MainActivity.targetPackage)
        builder.addDnsServer("8.8.8.8")
        // ipv4
        if (hasIPv4) {
            builder.addAddress(PRIVATE_VLAN4_CLIENT, 30)
            builder.addRoute("0.0.0.0", 0)
        }
        // ipv6
        if (hasIPv6) {
            builder.addAddress(PRIVATE_VLAN6_CLIENT, 126)
            builder.addRoute("::", 0)
        }

        val vpnDescriptor = builder.establish() ?: return
        this.vpnDescriptor = vpnDescriptor

        val tun = TUN().apply {
            fileDescriber = vpnDescriptor.fd
            mtu = VPN_MTU
            iPv6Config = when {
                hasIPv4 && hasIPv6 -> Libmitm.IPv6Enable
                hasIPv4 -> Libmitm.IPv6Disable
                hasIPv6 -> Libmitm.IPv6Only
                else -> error("invalid state")
            }
        }
        this.tun = tun
        tun.start()
        logInfo("netstack started")
        isActive = true
        try {
            MinecraftRelay.announceRelayUp()
            serviceListeners.forEach { it.onServiceStarted() }
        } catch (t: Throwable) {
            logError("start callback", t)
        }
    }

    private fun stopVPN() {
        isActive = false
        vpnDescriptor?.close()
        tun?.let {
            try {
                serviceListeners.forEach { l -> l.onServiceStopped() }
            } catch (t: Throwable) {
                logError("stop callback", t)
            }
            Thread(it::close).start()
        }
    }

    private fun checkNetState(): Pair<Boolean, Boolean> {
        val connectivityManager = this.getSystemService(CONNECTIVITY_SERVICE) as ConnectivityManager
        val activeNetwork = connectivityManager.getLinkProperties(connectivityManager.activeNetwork ?: return true to false) ?: return true to false
        val interfaceName = activeNetwork.interfaceName

        val networkInterfaces = NetworkInterface.getNetworkInterfaces()
        while (networkInterfaces.hasMoreElements()) {
            val ni = networkInterfaces.nextElement()
            if (ni.name != interfaceName) continue

            var hasIPv4 = false
            var hasIPv6 = false
            for (addr in ni.interfaceAddresses) {
                if (addr.address is Inet6Address) {
                    hasIPv6 = true
                } else if (addr.address is Inet4Address) {
                    hasIPv4 = true
                }
            }
            return hasIPv4 to hasIPv6
        }

        return true to false
    }

    private fun createNotification(): Notification {
        val flag = PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT

        val intent = Intent(this, MainActivity::class.java)
        intent.addCategory(Intent.CATEGORY_LAUNCHER)
        intent.action = Intent.ACTION_MAIN
        val pendingIntent = PendingIntent.getActivity(this, 0, intent, flag)

        val stopIntent = Intent(ACTION_STOP)
        stopIntent.setPackage(packageName)
        val pendingIntent1 = PendingIntent.getForegroundService(this, 1, stopIntent, flag)

        val builder = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle(getString(R.string.app_name))
            .setContentText(getString(
                R.string.proxy_notification, getString(R.string.app_name), packageManager.getApplicationName(MainActivity.targetPackage)))
            .setSmallIcon(R.drawable.notification_icon)
            .setLargeIcon(BitmapFactory.decodeResource(resources, R.mipmap.ic_launcher))
            .setOngoing(true)
            .setContentIntent(pendingIntent)
            .addAction(R.drawable.notification_icon, getString(R.string.dashboard_fab_disconnect), pendingIntent1)

        return builder.build()
    }

    companion object {
        const val ACTION_START = "dev.sora.libmitm.vpn.start"
        const val ACTION_STOP = "dev.sora.libmitm.vpn.stop"
