import os, re
errors = []
for root, dirs, files in os.walk('app/src/main/java'):
    for f in files:
        if f.endswith('.kt'):
            path = os.path.join(root, f)
            with open(path, 'r', encoding='utf-8', errors='replace') as fh:
                content = fh.read()
            # Check for unresolved references that might cause issues
            if 'stringResource(' in content:
                # Check if R.string references exist in strings.xml
                pass
            # Check basic brace balance
            open_braces = content.count('{')
            close_braces = content.count('}')
            if open_braces != close_braces:
                errors.append(f"{path}: brace mismatch {open_braces} vs {close_braces}")
            # Check parentheses balance in non-comment lines
            lines = content.split('\n')
            for i, line in enumerate(lines, 1):
                if not line.strip().startswith('//') and not line.strip().startswith('*'):
                    if line.count('(') != line.count(')'):
                        # Might be multi-line, skip if line ends with comma or obvious continuation
                        stripped = line.strip()
                        if not stripped.endswith(',') and not stripped.endswith('(') and not stripped.startswith(')'):
                            if '(' in stripped or ')' in stripped:
                                pass  # too many false positives
if errors:
    print("POTENTIAL ISSUES:")
    for e in errors[:10]:
        print(e)
else:
    print("No obvious syntax issues detected.")
EOF
